/**
 * Icons module — Lucide SVGs first, LineIcons font fallback.
 */
const Icons = class {
    /** @type {Map<string, string>} Font glyph name mapping (fallback) */
    static #fontMap = new Map(Object.entries(ICON_MAP));

    /** @type {Map<string, string>} SVG icon registry (primary) */
    static #svgMap = new Map(Object.entries(SVG_ICONS));

    /** Named stroke presets (for SVG fallbacks) */
    static #STROKE = { regular: 1, medium: 1.5, bold: 2 };

    static #sw(v) {
        if (v == null) return 2;
        if (typeof v === 'string') return Icons.#STROKE[v] ?? 2;
        return v;
    }

    /**
     * Get an icon as a DOM Element.
     * Returns <svg> for Lucide/SVG icons, <i> for font fallback.
     * @param {string} name
     * @param {object} [opts]
     * @param {number} [opts.size]              — icon size in px (default 24)
     * @param {number|string} [opts.strokeWidth] — stroke width for SVG icons
     * @param {string} [opts.class]             — extra CSS class(es)
     * @returns {HTMLElement|SVGSVGElement|null}
     */
    static el(name, opts = {}) {
        // SVG first (Lucide + custom)
        const inner = Icons.#svgMap.get(name);
        if (inner) {
            const size = opts.size ?? 24;
            const sw   = Icons.#sw(opts.strokeWidth);
            const cls  = opts.class ? ` ${opts.class}` : '';

            const NS  = SVG_NS;
            const svg = document.createElementNS(NS, 'svg');
            svg.setAttribute('xmlns', NS);
            svg.setAttribute('width', size);
            svg.setAttribute('height', size);
            svg.setAttribute('viewBox', '0 0 24 24');
            svg.setAttribute('fill', 'none');
            svg.setAttribute('stroke', 'currentColor');
            svg.setAttribute('stroke-width', sw);
            svg.setAttribute('stroke-linecap', 'round');
            svg.setAttribute('stroke-linejoin', 'round');
            svg.setAttribute('class', `rz-icon rz-icon-${name}${cls}`);
            svg.setAttribute('aria-hidden', 'true');
            svg.innerHTML = inner;

            return svg;
        }

        // Font fallback (LineIcons)
        const glyphName = Icons.#fontMap.get(name);
        if (glyphName) {
            const cls  = opts.class ? ` ${opts.class}` : '';
            const size = opts.size ?? 24;
            const el   = document.createElement('i');
            el.className = `ri-${glyphName} rz-icon rz-icon-${name}${cls}`;
            el.style.fontSize = `${size}px`;
            el.setAttribute('aria-hidden', 'true');
            return el;
        }

        console.warn('Icons: unknown icon →', name);
        return null;
    }

    /**
     * Get an icon as an HTML markup string.
     * Returns <svg> for Lucide/SVG icons, <i> for font fallback.
     * @param {string} name
     * @param {object} [opts] — same as el()
     * @returns {string}
     */
    static svg(name, opts = {}) {
        // SVG first (Lucide + custom)
        const inner = Icons.#svgMap.get(name);
        if (inner) {
            const size = opts.size ?? 24;
            const sw   = Icons.#sw(opts.strokeWidth);
            const cls  = opts.class ? ` ${opts.class}` : '';
            return `<svg xmlns="http://www.w3.org/2000/svg" width="${size}" height="${size}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="${sw}" stroke-linecap="round" stroke-linejoin="round" class="rz-icon rz-icon-${name}${cls}" aria-hidden="true">${inner}</svg>`;
        }

        // Font fallback (LineIcons)
        const glyphName = Icons.#fontMap.get(name);
        if (glyphName) {
            const cls  = opts.class ? ` ${opts.class}` : '';
            const size = opts.size ?? 24;
            return `<i class="ri-${glyphName} rz-icon rz-icon-${name}${cls}" style="font-size:${size}px" aria-hidden="true"></i>`;
        }

        return '';
    }

    /**
     * Inject an icon into an element (replaces innerHTML).
     * @param {string|Element} selector
     * @param {string} name
     * @param {object} [opts] — same as el()
     */
    static inject(selector, name, opts = {}) {
        const el = razyui.isStr(selector)
            ? document.querySelector(selector)
            : selector;

        if (!el) return;
        const iconEl = Icons.el(name, opts);
        if (!iconEl) return;

        el.innerHTML = '';
        el.appendChild(iconEl);
    }

    /**
     * Check if an icon exists.
     * @param {string} name
     * @returns {boolean}
     */
    static has(name) {
        return Icons.#fontMap.has(name) || Icons.#svgMap.has(name);
    }

    /**
     * Get all icon names.
     * @returns {string[]}
     */
    static list() {
        return [...new Set([...Icons.#fontMap.keys(), ...Icons.#svgMap.keys()])];
    }

    /**
     * Get total icon count.
     * @returns {number}
     */
    static get count() {
        return new Set([...Icons.#fontMap.keys(), ...Icons.#svgMap.keys()]).size;
    }

    /**
     * Register a custom SVG icon.
     * @param {string} name
     * @param {string} svgInner — SVG inner content for 24\xD724 viewBox
     */
    static register(name, svgInner) {
        Icons.#svgMap.set(name, svgInner);
    }

    /**
     * Register multiple custom SVG icons.
     * @param {Object<string, string>} icons
     */
    static registerAll(icons) {
        for (const [name, data] of Object.entries(icons)) {
            Icons.#svgMap.set(name, data);
        }
    }

    /**
     * Remove an icon.
     * @param {string} name
     */
    static remove(name) {
        Icons.#fontMap.delete(name);
        Icons.#svgMap.delete(name);
    }
};

export default Icons;
export const stylesheet = 'razyui-icons.css';
razyui.Icons = Icons;
